        System.out.println(root.children.isEmpty());
        System.out.println(root.isEndOfWord);
    }
}

import java.util.HashMap;
import java.util.Map;

public class Main {
    static class TrieNode {
        Map<Character, TrieNode> children = new HashMap<>();
        boolean isEndOfWord;
    }

    static TrieNode root = new TrieNode();

    static void insert(String word) {
        TrieNode current = root;
        for (char c : word.toCharArray()) {
            current.children.putIfAbsent(c, new TrieNode());
            current = current.children.get(c);
        }
        current.isEndOfWord = true;
    }

    public static void main(String[] args) {
        insert("cat");
        insert("car");
        insert("dog");

        System.out.println(root.children.keySet());
    }
}

import java.util.HashMap;
import java.util.Map;

public class Main {
    static class TrieNode {
        Map<Character, TrieNode> children = new HashMap<>();
        boolean isEndOfWord;
    }

    static TrieNode root = new TrieNode();

    static void insert(String word) {
        TrieNode current = root;
        for (char c : word.toCharArray()) {
            current.children.putIfAbsent(c, new TrieNode());
            current = current.children.get(c);
        }
        current.isEndOfWord = true;
    }

    static boolean search(String word) {
        TrieNode current = root;
        for (char c : word.toCharArray()) {
            if (!current.children.containsKey(c)) {
                return false;
            }
            current = current.children.get(c);
        }
        return current.isEndOfWord;
    }

    public static void main(String[] args) {
        insert("cat");
        insert("car");

        System.out.println(search("cat"));
        System.out.println(search("ca"));
        System.out.println(search("cats"));
    }
}

